INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-7ec62a85-moex-00262', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '甲因積欠交通違規罰單新臺幣18,000元，主管機關經催討後仍未繳納，移送行政執行。依行政執行法 規定，執行機關之下列執行行為何者違法？', '["於星期一上午8時對於甲之動產進行查封", "於履行期間屆滿後3年通知甲報告其財產狀況，之後逾3年始進行查封", "命甲報告財產狀況而甲不為報告，認應強制其到場而聲請法院裁定拘提", "於查明甲之經濟狀況後，認為其無法一次完納，經主管機關同意准其分期繳納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00263', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政執行法上之管收，下列敘述何者正確？', '["義務人不繳納怠金及代履行費用，並無適用管收相關規定之可能", "涉及義務人人身自由之限制，行政執行官應自拘提時起24小時內作成管收處分", "義務人如不服管收之決定，得準用民事訴訟法相關規定提出救濟，但管收之執行並不停止", "管收期限最長為3個月，義務人經管收期滿後，所負之公法上金錢給付義務視為已履行而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00264', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '消防隊為救火破壞門窗直接進入甲之住宅實施灌救。甲依法請求補償門窗損害新臺幣（下同）5萬元， 但主管機關僅核給1萬元，就此差額，甲應如何救濟？', '["向主管機關協議請求國家賠償", "逕向行政法院提起一般給付之訴", "提起訴願請求差額賠償", "循序提起課予義務訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00265', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者非屬行政程序法所稱之行政程序？', '["考試院修正專門職業及技術人員考試總成績計算規則", "公路監理機關與汽車修理廠締結汽車委託檢驗契約", "警察機關於轄區內進行巡邏", "建築主管機關處理人民對拆除違建疏失提出之舉發"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00266', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依行政程序法規定，聽證程序自何時開始，於何時終結？', '["當事人提出聽證申請開始；行政機關就該事件作成決定即屬終結", "以主持人就事實或法律問題詢問當事人或其他到場人開始；待所有問答均結束後即終結", "從聽證主持人說明案由開始；待當事人充分陳述意見，事件已達可為決定之程度者，即應終結", "上級機關核准進行聽證開始；將聽證紀錄呈報上級機關時終結"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00267', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政程序法中有關閱覽卷宗之規定，下列何者正確？', '["任何人均得請求閱覽、抄錄行政程序有關卷宗資料", "當事人得就未給予閱覽卷宗之處置，直接提起訴願", "閱覽卷宗時如發現其中資料關於他人之記載有錯誤，得請求更正", "適用分離原則，故涉及公務機密之文書資料中，如無保密必要之部分，仍應准許閱覽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00268', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '訴願文書之寄存送達，應依何法律行之，送達生效時點為何？', '["適用訴願法規定，自寄存時發生效力", "依訴願法準用行政程序法，自寄存時發生效力", "依訴願法準用行政訴訟法，自寄存日起經10日發生效力", "依訴願法準用民事訴訟法，自寄存日起經10日發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00269', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列訴願事件，何者不得逕為不受理之決定？', '["對已確定之訴願決定不服，重行提起訴願", "對已撤回之訴願，重行提起訴願", "未成年人自行提起訴願", "當事人對行政程序中駁回陳述意見申請之決定，提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00270', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '交通部依法委任所屬公路總局辦理汽車燃料使用費之徵收，對此使用費徵收之處分不服提起訴願，下 列何者為訴願管轄機關？', '["交通部公路總局", "交通部", "行政院", "財政部所屬國稅局"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00271', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '人民對下列何者不服時得提起訴願？', '["主管機關拒絕開闢道路之請求", "主管機關在店家門口劃設紅線", "主管機關調整某區收垃圾之時間", "主管機關對違章建築拆除之執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL)
